var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"STAR_PROMISE_NULL_NULL","text":{"KOREA":"응 보라야. 무슨 일이고?","JPN":"うん。シホ、どないしたん？","ENG":"Yeah, Bora. What's up?","TWN":"嗯，寶拉，什麼事？"},"stage":{"bg":"CORRIDOR_05","slots":{"L":null,"C":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"VIOLET_LEGACY_NULL_NPC","text":{"KOREA":"출국하는 거야……? 일 때문에?","JPN":"出国するの……？　仕事で？","ENG":"Are you going overseas... for work?","TWN":"要出國嗎……？因為工作？"},"stage":{"bg":"CORRIDOR_05","slots":{"L":null,"C":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"STAR_PROMISE_NULL_NULL","text":{"KOREA":"그래. 내 지금 비행기 타기 직전이다.","JPN":"うん。もう飛行機乗るとこやね。","ENG":"Yeah. I was just about to board the plane.","TWN":"對，我現在正要登機。"},"stage":{"bg":"CORRIDOR_05","slots":{"L":null,"C":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"STAR_PROMISE_NULL_NULL","text":{"KOREA":"이제 내도 일하러 가야지 안 긋나?","JPN":"そろそろウチも仕事に行かないとな。","ENG":"I need to get back to my work, dontcha think?","TWN":"我也該去工作了，不是嗎？"},"stage":{"bg":"CORRIDOR_05","slots":{"L":null,"C":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"STAR_PROMISE_NULL_NULL","text":{"KOREA":"아참, 내 나중에 말해 주려 했는데, 카운터즈 레거시 잘 즐기고 간다.","JPN":"そうや、あとで言おう思うてたけど、カウンターズ・レガシーめっちゃ楽しませてもらったで。","ENG":"Oh, and I was gonna tell ya later, but I had fun in Counters Legacy.","TWN":"啊，對了，我本來打算以後告訴你的，制裁者的遺產我玩得很開心。"},"stage":{"bg":"CORRIDOR_05","slots":{"L":null,"C":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"STAR_PROMISE_NULL_NULL","text":{"KOREA":"아하하, 네 덕에 우리가 간직했던 추억을 지킬 수 있어서 고마웠다.","JPN":"あんたのおかげで、ウチらの思い出守れてほんまに嬉しかったわ。","ENG":"Ah hah hah! Our memories are kept alive thanks to you.","TWN":"哈哈哈，多虧了你，我們才能守護住那些珍貴的回憶，真是謝謝你了。"},"stage":{"bg":"CORRIDOR_05","slots":{"L":null,"C":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"VIOLET_LEGACY_NULL_NPC","text":{"KOREA":"……리네야.","JPN":"……マリ。","ENG":"...Rinae.","TWN":"……璃奈……"},"stage":{"bg":"CORRIDOR_05","slots":{"L":null,"C":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"VIOLET_LEGACY_NULL_NPC","text":{"KOREA":"들어줘…… 부탁.","JPN":"聞いて……お願い。","ENG":"I need... a favor.","TWN":"拜託你……一件事。"},"stage":{"bg":"CORRIDOR_05","slots":{"L":null,"C":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"STAR_PROMISE_NULL_NULL","text":{"KOREA":"응? 무슨 일인데?","JPN":"うん？　どないした？","ENG":"Hmm? What is it?","TWN":"嗯？什麼事？"},"stage":{"bg":"CORRIDOR_05","slots":{"L":null,"C":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"RULER_JUNIOR_NULL_NULL","text":{"KOREA":"크윽, 이 몬스터들 만만치 않아요!","JPN":"くっ……このモンスターたち、手強いです！","ENG":"Kgh, these monsters are strong!","TWN":"呃，這些怪物不好對付！"},"stage":{"bg":"COUNTERSIDE_GREEN","slots":{"L":null,"C":{"char_id":"RULER_JUNIOR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"당연하지, 여긴 나 정도의 실력이 없으면 엄두도 못 내는 던전이라고.","JPN":"当り前よ。ここは私ぐらいの実力がない人は近寄れないダンジョンなのよ。","ENG":"Of course they are. Only someone as skilled as I can even dare to enter this dungeon.","TWN":"當然了，這裡是沒有我這種實力的人根本不敢涉足的副本。"},"stage":{"bg":"COUNTERSIDE_GREEN","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"하핫, 오랜만에 재밌어졌어. 그럼 슬슬 진심으로…….","JPN":"あはは、久しぶりに面白くなったね。じゃあそろそろ本気で……","ENG":"Haha, this is getting fun. Guess it's time I stopped fooling around and–","TWN":"哈哈，好久沒有這麼有趣了。那麼差不多該認真了……"},"stage":{"bg":"COUNTERSIDE_GREEN","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"PLAYER_LAGACY_NULL_EXTRA","text":{"KOREA":"괜찮나? 우리가 조금이라도 늦었으면 큰일 날 뻔했군.","JPN":"大丈夫か？　私たちが少しでも遅れて来たら大変なことになるとこだったな。","ENG":"You okay? You could've been in big trouble if we were a second late.","TWN":"你還好嗎？我們要是再來晚一點就糟了。"},"stage":{"bg":"COUNTERSIDE_GREEN","slots":{"L":{"char_id":"PLAYER_LAGACY_NULL_EXTRA","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PLAYER_LAGACY_NULL_EXTRAB","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"PLAYER_LAGACY_NULL_EXTRAB","text":{"KOREA":"하하, 너희들 방금 히어로를 찾고 있다 했지?","JPN":"はは、君たち、ヒーローを探しているんだろ？","ENG":"Haha, you said that you were looking for a hero, right?","TWN":"哈哈，你們剛才說在找英雄對吧？"},"stage":{"bg":"COUNTERSIDE_GREEN","slots":{"L":{"char_id":"PLAYER_LAGACY_NULL_EXTRA","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PLAYER_LAGACY_NULL_EXTRAB","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"PLAYER_LAGACY_NULL_EXTRAB","text":{"KOREA":"히어로라면 바로 우리를 말하는 거 아니겠어? \xA0","JPN":"ヒーローといえば俺たちのことじゃないか？\xA0 ","ENG":"Well, guess you've found them now!\xA0 ","TWN":"如果說到英雄，那不就是在說我們嗎？"},"stage":{"bg":"COUNTERSIDE_GREEN","slots":{"L":{"char_id":"PLAYER_LAGACY_NULL_EXTRA","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PLAYER_LAGACY_NULL_EXTRAB","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"뭐, 뭐야……?!","JPN":"な、何なの……？","ENG":"W-what...?!","TWN":"什，什麼啊……？！"},"stage":{"bg":"COUNTERSIDE_GREEN","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"이번에 유입된 일반 유저 분들인 것 같아요.","JPN":"今回ゲームを始めた一般ユーザーの方々のようです。","ENG":"I think they are the normal players who just started playing the game.","TWN":"好像是這次新進來的普通玩家。"},"stage":{"bg":"COUNTERSIDE_GREEN","slots":{"L":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"저기…… 도와주셔서 감사하지만 저희가 찾는 히어로는 아닌 것 같아요.","JPN":"あの……助けてくださってありがとうございます。でもあたしたちが探してるヒーローとは違うみたいです。","ENG":"Um... Thanks for helping us, but I don't think you're the hero we're looking for.","TWN":"那個……雖然感謝你的幫助，但你似乎不是我們要找的英雄。"},"stage":{"bg":"COUNTERSIDE_GREEN","slots":{"L":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SPEAKER_JUNIOR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"SPEAKER_JUNIOR_NULL_NULL","text":{"KOREA":"우리가 찾는 히어로는 가면을 쓰고 있었어. 그리고 노멀 플레이어는 아닐 거라 생각해","JPN":"ぼくたちが探してるヒーローは仮面をつけてたんだ。あと、ノーマルプレイヤーではないと思う。","ENG":"The person we're looking for is wearing a mask. And I don't think he's a normal player like you.","TWN":"我們要找的英雄戴著面具，而且我認為他不會是普通玩家。"},"stage":{"bg":"COUNTERSIDE_GREEN","slots":{"L":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SPEAKER_JUNIOR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"PLAYER_LAGACY_NULL_EXTRA","text":{"KOREA":"그 노멀 플레이어란 말 좀 그만하지? 여기선 우리 모두 동등하잖아.","JPN":"そのノーマルプレイヤーって言い方やめてもらえないか？　ここではみんな平等だろ。","ENG":"Will you quit it with the \\"normal player\\" crap? In here, we're all equals.","TWN":"能不能別再說什麼普通玩家了？在這裡我們都是平等的。"},"stage":{"bg":"COUNTERSIDE_GREEN","slots":{"L":{"char_id":"PLAYER_LAGACY_NULL_EXTRA","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PLAYER_LAGACY_NULL_EXTRAB","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"PLAYER_LAGACY_NULL_EXTRAB","text":{"KOREA":"카운터만 영웅이 될 수 있는 것도 아니잖아. 우리도 충분히……","JPN":"カウンターだけが英雄になれるわけでもない。俺たちだって十分……","ENG":"And it's not like only Counters can become heroes. We're as capable as–","TWN":"並不是只有制裁者才能成為英雄，我們也完全可以……"},"stage":{"bg":"COUNTERSIDE_GREEN","slots":{"L":{"char_id":"PLAYER_LAGACY_NULL_EXTRA","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PLAYER_LAGACY_NULL_EXTRAB","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"하하, 아티팩트로 재미 좀 보니까 현실과 구분을 못 하는 것 같은데.","JPN":"はは、アーティファクトの力に酔いしれて現実と区別がつかなくなったみたいだけど。","ENG":"Haha! Guess you can't tell what's real and what's not because of that Artifact.","TWN":"哈哈，用了人造神器之後好像分不清現實了。"},"stage":{"bg":"COUNTERSIDE_GREEN","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"영웅은 한 명으로 족해. 인류의 영웅은 바로 이 몸이 될 테니까.","JPN":"英雄は1人で十分よ。人類の英雄はこのナイエル様がなるんだから。","ENG":"One hero's enough. And that's going to be me.","TWN":"英雄只需要一個，而人類的英雄將會是我。"},"stage":{"bg":"COUNTERSIDE_GREEN","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}}]`);export{e as default};